mapper.select:
SELECT


            DATE_FORMAT(start_time, '%Y-%m')


            DATE_FORMAT(start_time, '%m-%d')


            DATE_FORMAT(start_time, '%m-%d %H:00')

     AS time_label,
    COALESCE(SUM(CASE WHEN status = '00' THEN 1 ELSE 0 END), 0) AS success,
    COALESCE(SUM(CASE WHEN status = '01' THEN 1 ELSE 0 END), 0) AS failed,
    COALESCE(SUM(CASE WHEN status = '02' THEN 1 ELSE 0 END), 0) AS partial,
    COALESCE(SUM(CASE WHEN status = '03' THEN 1 ELSE 0 END), 0) AS dead_letter,
    COALESCE(ROUND(AVG()), 0) AS avg_latency_ms
FROM rule_bridge_execution_trace

    AND start_time IS NOT NULL


            AND trace_id = #{query.traceId}


            AND bridge_rule_id = #{query.bridgeRuleId}


            AND direction = #{query.direction}


            AND trigger_source = #{query.triggerSource}


            AND product_identification = #{query.productIdentification}


            AND device_identification = #{query.deviceIdentification}


            AND action_type = #{query.actionType}


            AND status = #{query.status}


            AND start_time >= #{query.startTimeBegin}


            AND start_time <= #{query.startTimeEnd}



GROUP BY time_label
ORDER BY MIN(start_time)

SELECT
    bridge_rule_id AS bridge_rule_id,
    COUNT(1) AS trigger_count,
    COALESCE(SUM(CASE WHEN status = '00' THEN 1 ELSE 0 END), 0) AS success,
    COALESCE(SUM(CASE WHEN status = '01' THEN 1 ELSE 0 END), 0) AS failed,
    COALESCE(SUM(CASE WHEN status = '03' THEN 1 ELSE 0 END), 0) AS dead_letter
FROM rule_bridge_execution_trace

    AND bridge_rule_id IS NOT NULL


            AND trace_id = #{query.traceId}


            AND bridge_rule_id = #{query.bridgeRuleId}


            AND direction = #{query.direction}


            AND trigger_source = #{query.triggerSource}


            AND product_identification = #{query.productIdentification}


            AND device_identification = #{query.deviceIdentification}


            AND action_type = #{query.actionType}


            AND status = #{query.status}


            AND start_time >= #{query.startTimeBegin}


            AND start_time <= #{query.startTimeEnd}



GROUP BY bridge_rule_id
ORDER BY trigger_count DESC, bridge_rule_id DESC
LIMIT #{limit}
